SELECT metric_name
FROM quality_metrics
WHERE metric_id = 1;

SELECT COUNT(image_id) 
FROM image_quality_assessments 
WHERE metric_id = 1;

SELECT metric_name
FROM quality_metrics
ORDER BY metric_name;

SELECT user_name
FROM users
ORDER BY user_name ASC;

SELECT COUNT(*) AS distortion_count
FROM distortion_types
WHERE strftime('%Y', created_at) = '2023';

SELECT distortion_type_name
FROM distortion_types
WHERE distortion_type_id = 1;
